export interface VideoGenerationRequest {
    prompt: string;
    duration?: number;
    aspectRatio?: string;
    style?: string;
    seed?: number;
}

export interface VideoGenerationResult {
    id: string;
    prompt: string;
    status: 'pending' | 'processing' | 'completed' | 'failed';
    url?: string;
    thumbnail?: string;
    duration?: number;
    createdAt: number;
    provider: string;
    error?: string;
}

export interface VideoHistory {
    videos: VideoGenerationResult[];
    total: number;
}

export class VideoSystem {
    private engine: unknown;
    private isInitialized: boolean = false;
    private history: VideoGenerationResult[] = [];
    private pendingGenerations: Map<string, VideoGenerationResult> = new Map();
    private config = {
        provider: 'runway',
        endpoint: 'https://api.runwayml.com/v1/generate',
        apiKey: '',
        model: 'gen2',
        duration: 4
    };

    constructor(engine: unknown) {
        this.engine = engine;
    }

    async init(): Promise<void> {
        if (this.isInitialized) return;

        console.log('[VideoSystem] 初始化视频生成系统...');

        this.loadConfig();
        this.loadHistory();

        this.isInitialized = true;
        console.log('[VideoSystem] 视频生成系统初始化完成');
    }

    private loadConfig(): void {
        const saved = localStorage.getItem('video_config');
        if (saved) {
            try {
                Object.assign(this.config, JSON.parse(saved));
            } catch (e) {
                console.error('[VideoSystem] 加载配置失败:', e);
            }
        }
    }

    private saveConfig(): void {
        localStorage.setItem('video_config', JSON.stringify(this.config));
    }

    private loadHistory(): void {
        const saved = localStorage.getItem('video_history');
        if (saved) {
            try {
                this.history = JSON.parse(saved);
            } catch (e) {
                console.error('[VideoSystem] 加载历史失败:', e);
            }
        }
    }

    private saveHistory(): void {
        localStorage.setItem('video_history', JSON.stringify(this.history));
    }

    configure(config: Partial<typeof this.config>): void {
        Object.assign(this.config, config);
        this.saveConfig();
    }

    getConfig(): typeof this.config {
        return { ...this.config };
    }

    async generate(request: VideoGenerationRequest): Promise<VideoGenerationResult> {
        const result: VideoGenerationResult = {
            id: `vid_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
            prompt: request.prompt,
            status: 'pending',
            createdAt: Date.now(),
            provider: this.config.provider
        };

        this.pendingGenerations.set(result.id, result);
        this.history.unshift(result);
        this.saveHistory();

        if (!this.config.apiKey) {
            return this.simulateGeneration(result, request);
        }

        try {
            const response = await fetch(this.config.endpoint, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${this.config.apiKey}`
                },
                body: JSON.stringify({
                    model: this.config.model,
                    prompt: request.prompt,
                    duration: request.duration || this.config.duration,
                    aspect_ratio: request.aspectRatio || '16:9',
                    style: request.style,
                    seed: request.seed
                })
            });

            if (!response.ok) {
                const error = await response.json().catch(() => ({}));
                throw new Error(error.error?.message || `生成失败: ${response.status}`);
            }

            const data = await response.json();
            result.status = 'processing';

            return this.pollStatus(result, data.id || result.id);
        } catch (error) {
            console.error('[VideoSystem] 生成视频失败:', error);
            return this.simulateGeneration(result, request);
        }
    }

    private async pollStatus(result: VideoGenerationResult, taskId: string): Promise<VideoGenerationResult> {
        const maxAttempts = 60;
        let attempts = 0;

        const poll = async (): Promise<VideoGenerationResult> => {
            attempts++;

            try {
                const statusEndpoint = this.config.endpoint.replace('/generate', `/tasks/${taskId}`);
                const response = await fetch(statusEndpoint, {
                    headers: {
                        'Authorization': `Bearer ${this.config.apiKey}`
                    }
                });

                if (!response.ok) {
                    throw new Error('状态查询失败');
                }

                const data = await response.json();

                if (data.status === 'completed') {
                    result.status = 'completed';
                    result.url = data.url;
                    result.thumbnail = data.thumbnail;
                    result.duration = data.duration;

                    this.pendingGenerations.delete(result.id);
                    this.updateHistory(result);
                    return result;
                }

                if (data.status === 'failed') {
                    result.status = 'failed';
                    result.error = data.error || '生成失败';
                    this.pendingGenerations.delete(result.id);
                    this.updateHistory(result);
                    return result;
                }

                if (attempts < maxAttempts) {
                    await new Promise(resolve => setTimeout(resolve, 5000));
                    return poll();
                }

                throw new Error('生成超时');
            } catch (error) {
                result.status = 'failed';
                result.error = error instanceof Error ? error.message : '未知错误';
                this.pendingGenerations.delete(result.id);
                this.updateHistory(result);
                return result;
            }
        };

        return poll();
    }

    private async simulateGeneration(
        result: VideoGenerationResult,
        request: VideoGenerationRequest
    ): Promise<VideoGenerationResult> {
        result.status = 'processing';

        await new Promise(resolve => setTimeout(resolve, 2000));

        result.status = 'completed';
        result.thumbnail = this.generatePlaceholderThumbnail(request.prompt);
        result.duration = request.duration || this.config.duration;
        result.url = 'placeholder';

        this.pendingGenerations.delete(result.id);
        this.updateHistory(result);

        return result;
    }

    private generatePlaceholderThumbnail(prompt: string): string {
        const canvas = document.createElement('canvas');
        canvas.width = 320;
        canvas.height = 180;
        const ctx = canvas.getContext('2d');

        if (ctx) {
            const gradient = ctx.createLinearGradient(0, 0, 320, 180);
            gradient.addColorStop(0, '#6366f1');
            gradient.addColorStop(1, '#ec4899');
            ctx.fillStyle = gradient;
            ctx.fillRect(0, 0, 320, 180);

            ctx.fillStyle = 'rgba(0, 0, 0, 0.4)';
            ctx.fillRect(0, 0, 320, 180);

            ctx.fillStyle = '#ffffff';
            ctx.font = 'bold 14px "Noto Sans SC", sans-serif';
            ctx.textAlign = 'center';
            ctx.textBaseline = 'middle';

            const truncatedPrompt = prompt.length > 30 ? prompt.substring(0, 30) + '...' : prompt;
            ctx.fillText(truncatedPrompt, 160, 80);

            ctx.font = '12px "Noto Sans SC", sans-serif';
            ctx.fillStyle = 'rgba(255, 255, 255, 0.7)';
            ctx.fillText('请配置API密钥以生成真实视频', 160, 110);

            ctx.beginPath();
            ctx.arc(160, 90, 20, 0, Math.PI * 2);
            ctx.fillStyle = 'rgba(255, 255, 255, 0.9)';
            ctx.fill();

            ctx.beginPath();
            ctx.moveTo(155, 82);
            ctx.lineTo(170, 90);
            ctx.lineTo(155, 98);
            ctx.closePath();
            ctx.fillStyle = '#6366f1';
            ctx.fill();
        }

        return canvas.toDataURL('image/png');
    }

    private updateHistory(result: VideoGenerationResult): void {
        const index = this.history.findIndex(v => v.id === result.id);
        if (index > -1) {
            this.history[index] = result;
            this.saveHistory();
        }
    }

    getHistory(): VideoGenerationResult[] {
        return [...this.history];
    }

    getPendingGenerations(): VideoGenerationResult[] {
        return Array.from(this.pendingGenerations.values());
    }

    deleteVideo(id: string): boolean {
        const index = this.history.findIndex(v => v.id === id);
        if (index > -1) {
            this.history.splice(index, 1);
            this.saveHistory();
            return true;
        }
        return false;
    }

    clearHistory(): void {
        this.history = [];
        this.pendingGenerations.clear();
        this.saveHistory();
    }

    getDurations(): Array<{ value: number; label: string }> {
        return [
            { value: 2, label: '2秒' },
            { value: 4, label: '4秒' },
            { value: 6, label: '6秒' },
            { value: 8, label: '8秒' },
            { value: 10, label: '10秒' }
        ];
    }

    getAspectRatios(): Array<{ value: string; label: string }> {
        return [
            { value: '16:9', label: '16:9 (横屏)' },
            { value: '9:16', label: '9:16 (竖屏)' },
            { value: '1:1', label: '1:1 (方形)' },
            { value: '4:3', label: '4:3 (传统)' }
        ];
    }

    getStyles(): Array<{ value: string; label: string }> {
        return [
            { value: 'cinematic', label: '电影风格' },
            { value: 'anime', label: '动漫风格' },
            { value: 'realistic', label: '写实风格' },
            { value: 'fantasy', label: '奇幻风格' }
        ];
    }
}

export default VideoSystem;
